```cpp
// add_modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  using namespace sqlgen::literals;

  // Map table names to their corresponding struct types
  const auto conn = sqlgen::sqlite::connect(db_path).value();

  if (table_name == "Student") {
    using TableType = Student;
    auto result = sqlgen::insert<TableType>(conn, records).value();
  } else if (table_name == "Course") {
    using TableType = Course;
    auto result = sqlgen::insert<TableType>(conn, records).value();
  } else if (table_name == "Score") {
    using TableType = Score;
    auto result = sqlgen::insert<TableType>(conn, records).value();
  } else if (table_name == "Major") {
    using TableType = Major;
    auto result = sqlgen::insert<TableType>(conn, records).value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  using namespace sqlgen::literals;

  const auto conn = sqlgen::sqlite::connect(db_path).value();

  if (table_name == "Student") {
    using TableType = Student;
    auto condition = ("SNo"_c == record_id);
    auto set_op = set(col_name"_c" = new_value);
    auto result = (update<TableType> | where(condition) | set(set_op))(conn).value();
  } else if (table_name == "Course") {
    using TableType = Course;
    auto condition = ("CID"_c == std::stoi(record_id));
    auto set_op = set(col_name"_c" = new_value);
    auto result = (update<TableType> | where(condition) | set(set_op))(conn).value();
  } else if (table_name == "Score") {
    using TableType = Score;
    auto condition = ("ScID"_c == std::stoi(record_id));
    auto set_op = set(col_name"_c" = new_value);
    auto result = (update<TableType> | where(condition) | set(set_op))(conn).value();
  } else if (table_name == "Major") {
    using TableType = Major;
    auto condition = ("MID"_c == std::stoi(record_id));
    auto set_op = set(col_name"_c" = new_value);
    auto result = (update<TableType> | where(condition) | set(set_op))(conn).value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  using namespace sqlgen::literals;

  const auto conn = sqlgen::sqlite::connect(db_path).value();

  if (table_name == "Student") {
    using TableType = Student;
    auto condition = ("SNo"_c == record_id);
    auto result = (delete_from<TableType> | where(condition))(conn).value();
  } else if (table_name == "Course") {
    using TableType = Course;
    auto condition = ("CID"_c == std::stoi(record_id));
    auto result = (delete_from<TableType> | where(condition))(conn).value();
  } else if (table_name == "Score") {
    using TableType = Score;
    auto condition = ("ScID"_c == std::stoi(record_id));
    auto result = (delete_from<TableType> | where(condition))(conn).value();
  } else if (table_name == "Major") {
    using TableType = Major;
    auto condition = ("MID"_c == std::stoi(record_id));
    auto result = (delete_from<TableType> | where(condition))(conn).value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish a connection to the SQLite database.

2. **Table Mapping**: Maps string table names to their corresponding struct types (Student, Course, Score, Major) using conditional checks.

3. **Insert Operation**: Uses `sqlgen::insert<TableType>(conn, records)` to insert multiple records into the specified table.

4. **Update Operation**: 
   - Uses `update<TableType>` to start an update operation
   - Applies `where(condition)` to filter by primary key
   - Uses `set(column = new_value)` to update the specified column
   - Chains operations with the `|` operator

5. **Delete Operation**: 
   - Uses `delete_from<TableType>` to start a delete operation
   - Applies `where(condition)` to filter by primary key

6. **Type Conversion**: Converts string `record_id` to integer for non-Student tables where primary keys are integers.

7. **Error Handling**: Throws exceptions for unknown tables and failed operations.

The implementation follows sqlgen's fluent API pattern and properly handles the different data types for primary keys across various tables.

