```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Begin transaction
  auto transaction = sqlgen::begin_transaction(conn).value();

  // 3. Create delete statement with condition
  auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");

  // 4. Execute the delete operation within the transaction
  auto result = delete_stmt(conn);

  // 5. Commit the transaction
  if (result) {
    return transaction->commit().value();
  } else {
    transaction->rollback();
    return 1; // Return error code on failure
  }
}

} // namespace delete_inactive_users
```

