  create_table<Post>(conn);

  insert(conn, std::vector<User>{{1, "alice"}, {2, "bob"}, {3, "carol"}});
  insert(conn, std::vector<Post>{{1, 1, "2025-12-30 00:00:00"},
                                 {2, 1, "2024-01-01 00:00:00"},
                                 {3, 2, "2025-12-20 00:00:00"},
                                 {4, 3, "2023-01-01 00:00:00"}});

