std::vector<ValidatedProfile> trim_and_length_validation() {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create a read operation for UserProfile table with transformations
  auto read_operation = sqlgen::read<UserProfile> 
    | sqlgen::transform([](auto profile) {
        // Trim whitespace from name and email fields
        auto trimmed_name = sqlgen::trim(profile.name);
        auto trimmed_email = sqlgen::trim(profile.email);

        // Calculate lengths of trimmed fields
        int name_len = sqlgen::length(trimmed_name);
        int email_len = sqlgen::length(trimmed_email);

        // Map to ValidatedProfile structure
        return ValidatedProfile{
            .user_id = profile.user_id,
            .trimmed_name = std::move(trimmed_name),
            .trimmed_email = std::move(trimmed_email),
            .name_length = name_len,
            .email_length = email_len
        };
    });

  // Execute the read operation and return the result
  return read_operation(conn).value();
}

}  // namespace trim_and_length_validation
